#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    // Read n integers into a std::vector<int>, then use an iterator loop
    // to print the elements and report their sum (see the output format).

    return 0;
}

solution_code:
#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> vec{};
    for (int i{ 0 }; i < n; ++i)
    {
        int val{};
        std::cin >> val;
        vec.push_back(val);
    }

    int sum{ 0 };
    std::cout << "Elements:";
    for (auto it{ vec.begin() }; it != vec.end(); ++it)
    {
        std::cout << ' ' << *it;
        sum += *it;
    }
    std::cout << '\n';
    std::cout << "Sum: " << sum << '\n';

    return 0;
}

