    // Read 6 integers into arr, then use iterators to find the maximum
    // value and the index of its first occurrence.

    return 0;
}

solution_code:
#include <array>
#include <iostream>

int main()
{
    std::array<int, 6> arr{};
    for (auto it{ arr.begin() }; it != arr.end(); ++it)
        std::cin >> *it;

    auto maxIt{ arr.begin() };
    for (auto it{ arr.begin() }; it != arr.end(); ++it)
    {
        if (*it > *maxIt)
            maxIt = it;
    }

    std::cout << "Max: " << *maxIt << '\n';
    std::cout << "Position: " << (maxIt - arr.begin()) << '\n';

    return 0;
}
